  1	import * as React from 'react';
  2	import { ObjectStorageOverviewQueries } from '@odf/ocs/queries/object-storage';
  3	import { PrometheusMultilineUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-multi-utilization-item';
  4	import { ErrorCardBody } from '@odf/shared/generic/ErrorCardBody';
  5	import {
  6	  useCustomPrometheusPoll,
  7	  usePrometheusBasePath,
  8	} from '@odf/shared/hooks/custom-prometheus-poll';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import { humanizeNumber } from '@odf/shared/utils/humanize';
 11	import { parseMetricData } from '@odf/shared/utils/metrics';
 12	import { QueryWithDescription } from '@openshift-console/dynamic-plugin-sdk';
 13	import { UtilizationDurationDropdown } from '@openshift-console/dynamic-plugin-sdk-internal';
 14	import classNames from 'classnames';
 15	import * as _ from 'lodash-es';
 16	import { useNavigate } from 'react-router-dom-v5-compat';
 17	import {
 18	  Button,
 19	  ButtonVariant,
 20	  Card,
 21	  CardBody,
 22	  CardHeader,
 23	  CardProps,
 24	  CardTitle,
 25	  DescriptionList,
 26	  DescriptionListDescription,
 27	  DescriptionListGroup,
 28	  DescriptionListTerm,
 29	  Skeleton,
 30	} from '@patternfly/react-core';
 31	import { ArrowRightIcon } from '@patternfly/react-icons';
 32	import './ObjectStorageCard.scss';
 33	
 34	const BUCKETS_PROVISIONED_QUERIES: [
 35	  QueryWithDescription,
 36	  QueryWithDescription,
 37	] = [
 38	  {
 39	    query: ObjectStorageOverviewQueries.NOOBAA_BUCKETS_PROVISIONED,
 40	    desc: 'NooBaa',
 41	  },
 42	  { query: '', desc: 'RGW' }, // @TODO: add RGW query when metric is available.
 43	];
 44	
 45	export const ObjectStorageCard: React.FC<CardProps> = ({ className }) => {
 46	  const { t } = useCustomTranslation();
 47	  const navigate = useNavigate();
 48	  const [nbBucketsData, nbBucketsError, nbBucketsLoading] =
 49	    useCustomPrometheusPoll({
 50	      query: ObjectStorageOverviewQueries.NOOBAA_BUCKETS_PROVISIONED,
 51	      endpoint: 'api/v1/query' as any,
 52	      basePath: usePrometheusBasePath(),
 53	    });
 54	
 55	  const nbBuckets =
 56	    _.isEmpty(nbBucketsError) && !nbBucketsLoading
 57	      ? parseMetricData(nbBucketsData, humanizeNumber)[0]?.usedValue.value || 0
 58	      : 0;
 59	
 60	  return (
 61	    <Card className={classNames(className)} isFlat={true}>
 62	      <CardHeader
 63	        actions={
 64	          nbBuckets && {
 65	            actions: <UtilizationDurationDropdown />,
 66	          }
 67	        }
 68	      >
 69	        <CardTitle>{t('Object storage')}</CardTitle>
 70	      </CardHeader>
 71	      <CardBody>
 72	        {!nbBucketsLoading && !nbBucketsError && (
 73	          <>
 74	            <DescriptionList>
 75	              <DescriptionListGroup>
 76	                <DescriptionListTerm>
 77	                  {t('Buckets provisioned')}
 78	                </DescriptionListTerm>
 79	                <DescriptionListDescription>
 80	                  {nbBuckets}
 81	                </DescriptionListDescription>
 82	              </DescriptionListGroup>
 83	            </DescriptionList>
 84	            <PrometheusMultilineUtilizationItem
 85	              title={''}
 86	              queries={BUCKETS_PROVISIONED_QUERIES}
 87	              humanizeValue={humanizeNumber}
 88	              chartType="grouped-line"
 89	              className="odf-storage-card__chart"
 90	            />
 91	            <Button
 92	              variant={ButtonVariant.link}
 93	              icon={<ArrowRightIcon />}
 94	              iconPosition="end"
 95	              className="pf-v6-u-font-size-lg pf-v6-u-mt-md odf-cluster-card__storage-link"
 96	              component="a"
 97	              onClick={() => navigate('/odf/object-storage')}
 98	            >
 99	              {t('View buckets')}
100	            </Button>
101	          </>
102	        )}
103	        {nbBucketsLoading && !nbBucketsError && (
104	          <Skeleton
105	            height="100%"
106	            screenreaderText={t('Loading object storage data')}
107	          />
108	        )}
109	        {nbBucketsError && (
110	          <ErrorCardBody title={t('Object storage data not available.')} />
111	        )}
112	      </CardBody>
113	    </Card>
114	  );
115	};

